sql:
SELECT station_id, COUNT(ws_obs_id) AS total_observations
FROM weather_station_observations
GROUP BY station_id;

SELECT model_name, model_description, resolution 
FROM weather_forecast_models 
WHERE resolution > 5;

SELECT cond_name 
FROM weather_conditions 
ORDER BY cond_name;

SELECT COUNT(ws_obs_id) 
FROM weather_station_observations 
WHERE station_id = 1 AND obs_id = 1 AND instrument_id = 1;

SELECT cond_name, cond_description, cond_severity
FROM weather_conditions
ORDER BY cond_name ASC;

SELECT ws.station_id, ws.station_name, ws.location, ws.status
FROM weather_stations ws
LIMIT 10;

SELECT ws.station_id, ws.obs_id, ws.obs_time, ws.obs_value
FROM weather_station_observations ws
ORDER BY ws.obs_time ASC;

SELECT *
FROM weather_station_observations
WHERE station_id = 1;
